    public sealed class ThumbprintOrSubjectX509Validator : X509CertificateValidator
    {
        private readonly string[] _allowedThumbprints;
        private readonly string[] _allowedSubjectContains;

        public ThumbprintOrSubjectX509Validator(string[] allowedThumbprints, string[] allowedSubjectContains)
        {
            _allowedThumbprints = allowedThumbprints?.Where(s => !string.IsNullOrWhiteSpace(s)).Select(NormThumb).ToArray() ?? Array.Empty<string>();
            _allowedSubjectContains = allowedSubjectContains?.Where(s => !string.IsNullOrWhiteSpace(s)).ToArray() ?? Array.Empty<string>();
        }

        public override void Validate(X509Certificate2 certificate)
        {
            if (certificate == null) throw new ArgumentNullException(nameof(certificate));

            var thumb = NormThumb(certificate.Thumbprint ?? string.Empty);
            if (_allowedThumbprints.Length > 0 && _allowedThumbprints.Contains(thumb, StringComparer.OrdinalIgnoreCase))
                return;

            if (_allowedSubjectContains.Length > 0)
            {
                foreach (var token in _allowedSubjectContains)
                {
                    if (!string.IsNullOrWhiteSpace(certificate.Subject) &&
                        certificate.Subject.IndexOf(token, StringComparison.OrdinalIgnoreCase) >= 0)
                        return;
                }
            }

